const results = $.steps.fetchTasks.response.results || [];
const tasks = [];
results.forEach((block, i) => {
  const type = block.type || '';
  let text = '';
  if (block[type] && block[type].rich_text) {
    text = block[type].rich_text.map(t => t.plain_text || '').join('');
  }
  if (text.trim().length > 3) {
    const isDone = type === 'to_do' && block[type] && block[type].checked;
    tasks.push({ index: i + 1, text: text.trim().slice(0, 300), type: type, done: isDone || false });
  }
});

let taskSummary = '';
const pending = tasks.filter(t => !t.done);
const completed = tasks.filter(t => t.done);
pending.forEach(t => { taskSummary += '[ ] ' + t.text + '\n'; });
completed.forEach(t => { taskSummary += '[x] ' + t.text + '\n'; });

return { tasks, taskSummary, pendingCount: pending.length, completedCount: completed.length, totalCount: tasks.length };

const d = $.steps.extractTasks.output;
const focusAreas = $.input.focusAreas || '';
const today = new Date().toISOString().slice(0, 10);
const dayName = new Date().toLocaleDateString('en-US', { weekday: 'long' });

let prompt = 'You are a productivity and task management AI assistant. Analyze the task list and create an optimized daily plan.\n\n';
prompt += 'DATE: ' + dayName + ', ' + today + '\n';
prompt += 'TASKS: ' + d.pendingCount + ' pending, ' + d.completedCount + ' completed\n';
if (focusAreas) prompt += 'FOCUS AREAS: ' + focusAreas + '\n';
prompt += '\nTASK LIST:\n' + d.taskSummary + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Prioritize pending tasks using Eisenhower Matrix (urgent/important)\n';
prompt += '- Group related tasks into work blocks\n';
prompt += '- Estimate time for each task\n';
prompt += '- Suggest a time-blocked daily schedule\n';
prompt += '- Identify tasks that can be delegated or deferred\n';
prompt += '- Highlight tasks aligned with focus areas\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "dailyPlan": [\n';
prompt += '    {\n';
prompt += '      "timeBlock": "9:00-10:00",\n';
prompt += '      "task": "task description",\n';
prompt += '      "priority": "urgent-important|important|urgent|low",\n';
prompt += '      "estimatedMinutes": 30,\n';
prompt += '      "category": "deep-work|admin|communication|planning",\n';
prompt += '      "alignsWithFocus": true\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "executiveSummary": "overview of the day ahead",\n';
prompt += '  "topPriorities": ["most critical task 1", "most critical task 2", "most critical task 3"],\n';
prompt += '  "deferrable": ["task that can wait"],\n';
prompt += '  "delegatable": ["task that could be delegated"],\n';
prompt += '  "productivityTips": ["tip for today"],\n';
prompt += '  "completionProgress": "percentage of overall task completion"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { dailyPlan: [], executiveSummary: raw, topPriorities: [], deferrable: [], delegatable: [], productivityTips: [], completionProgress: '' }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Time Block', 'Task', 'Priority', 'Est. Minutes', 'Category', 'Aligns with Focus', 'Status']);
(ai.dailyPlan || []).forEach(p => {
  rows.push([today, p.timeBlock || '', p.task || '', p.priority || '', String(p.estimatedMinutes || ''), p.category || '', p.alignsWithFocus ? 'Yes' : 'No', 'Planned']);
});
return { rows, taskCount: rows.length - 1 };

const ai = $.steps.parseAI.output;
const d = $.steps.extractTasks.output;
const tasks = $.steps.buildSheetRows.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Daily Task Brief', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Pending:* ' + d.pendingCount + ' | *Completed:* ' + d.completedCount + ' | *Progress:* ' + (ai.completionProgress || 'N/A') } });
blocks.push({ type: 'divider' });

if (ai.executiveSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.executiveSummary.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

if (ai.topPriorities && ai.topPriorities.length > 0) {
  let priText = '*Top Priorities:*\n';
  ai.topPriorities.forEach((p, i) => { priText += ':red_circle: ' + (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: priText.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

let scheduleText = '*Today\'s Schedule:*\n';
(ai.dailyPlan || []).slice(0, 8).forEach(p => {
  const icon = p.priority === 'urgent-important' ? ':rotating_light:' : p.priority === 'important' ? ':star:' : p.priority === 'urgent' ? ':zap:' : ':white_circle:';
  scheduleText += icon + ' *' + p.timeBlock + '* ' + p.task + ' (' + (p.estimatedMinutes || '?') + 'min)\n';
});
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: scheduleText.slice(0, 1800) } });

if (ai.productivityTips && ai.productivityTips.length > 0) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':bulb: *Tip:* ' + ai.productivityTips[0] } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Plan saved to Sheets | Powered by Notion + Claude AI' }] });
const fallback = 'Task Brief: ' + d.pendingCount + ' pending, top 3: ' + (ai.topPriorities || []).slice(0, 3).join(', ');
return { blocks, fallback };
